
.status-card {
  width: 100%;
  max-width: 760px;
  margin: 0 auto;
  border: 1px solid var(--line-strong);
  background: var(--surface-paper);
  box-shadow: 3px 3px 0 var(--shadow-frame);
}

.panel-shell {
  padding: 15px;
  outline: none;
  animation: lcdPageIn 230ms ease-out both;
}

.profile-drawer {
  padding: 10px;
  border-bottom: 1px solid var(--line-strong);
  background: var(--accent-primary-soft);
}

.profile-drawer :deep(.profile-form) {
  box-shadow: none;
}

.panel-shell:focus-visible {
  box-shadow: inset 0 0 0 2px var(--accent-signal);
}

.status-footer {
  display: flex;
  align-items: center;
  justify-content: space-between;
  gap: 10px;
  padding: 5px 9px;
  border-top: 1px solid var(--line-soft);
  background: var(--surface-muted);
  color: var(--ink-muted);
  font-family: var(--font-data);
  font-size: 0.62rem;
}

@keyframes lcdPageIn {
  0% {
    opacity: 0.58;
    transform: translateX(4px);
    box-shadow: inset 12px 0 0 var(--accent-primary-soft);
  }

  100% {
    opacity: 1;
    transform: translateX(0);
    box-shadow: inset 0 0 0 transparent;
  }
}

@media (max-width: 520px) {
  .status-card {
    box-shadow: 1px 1px 0 var(--shadow-frame);
  }

  .panel-shell {
    padding: 12px 10px;
  }

  .profile-drawer {
    padding: 7px;
  }

  .status-footer {
    align-items: flex-start;
    flex-direction: column;
    gap: 1px;
  }
}

@media (prefers-reduced-motion: reduce) {
  .panel-shell {
    animation: none;
  }
}
