
.fame-panel {
  display: grid;
  grid-template-columns: repeat(2, minmax(0, 1fr));
  gap: 14px;
}

.fame-channel {
  padding: 13px;
  border: 1px solid var(--line-soft);
  background: var(--surface-raised);
}

.channel-heading {
  display: flex;
  align-items: flex-start;
  justify-content: space-between;
  gap: 12px;
  margin-bottom: 12px;
  padding-bottom: 7px;
  border-bottom: 1px dotted var(--line-soft);
}

.channel-heading h2 {
  margin: 1px 0 0;
  font-size: 0.95rem;
}

.channel-heading > strong {
  color: var(--accent-primary-strong);
  font-family: var(--font-data);
  font-size: 1.55rem;
  line-height: 1;
}

.channel-code {
  color: var(--accent-signal);
  font-family: var(--font-data);
  font-size: 0.66rem;
  letter-spacing: 0.06em;
}

.fame-channel p {
  margin: 12px 0 0;
  color: var(--ink-secondary);
  font-size: 0.82rem;
}

.scope-note {
  grid-column: 1 / -1;
  display: flex;
  align-items: flex-start;
  gap: 8px;
  margin: 0;
  color: var(--ink-muted);
  font-size: 0.75rem;
}

.scope-note span {
  display: inline-grid;
  flex: none;
  place-items: center;
  width: 16px;
  height: 16px;
  border: 1px solid var(--accent-signal);
  color: var(--accent-signal);
  font-family: var(--font-data);
}

@media (max-width: 560px) {
  .fame-panel {
    grid-template-columns: 1fr;
  }
}
